import React from 'react';
import { Link } from 'react-router-dom'; // Importa Link para la navegación interna

const Footer = () => {
  return (
    <footer style={styles.footerContainer}>
      <div style={styles.footerContent}>
        {/* Sección 1: Más información */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>más información</h3>
          <div style={styles.linksColumn}>
            <ul style={styles.linkList}>
              <li><Link to="/empresas" style={styles.link}>Empresas</Link></li>
              <li><Link to="/historia" style={styles.link}>Nuestra Historia</Link></li> {/* Enlace a "Acerca de" */}
              <li><a href="#" style={styles.link}>Novedades</a></li> {/* "reviews" */}
              <li><a href="#" style={styles.link}>Tienda</a></li> {/* "gift cards" / "shop" */}
              <li><a href="#" style={styles.link}>Productos</a></li> {/* "buy with fsa / hsa" */}
            </ul>
            <ul style={styles.linkList}>
              <li><a href="#" style={styles.link}>Recompensas</a></li> {/* "rewards" */}
              <li><a href="#" style={styles.link}>Recomienda un amigo</a></li> {/* "refer-a-friend" */}
              <li><a href="#" style={styles.link}>Únete al equipo</a></li> {/* "join the team" */}
              <li><Link to="/contacto" style={styles.link}>Contacto</Link></li> {/* Enlace a "Contacto" */}
            </ul>
          </div>
        </div>

        {/* Sección 2: Encuéntranos / Club de Correo / Redes Sociales */}
        <div style={styles.sectionCenter}>
          <h3 style={styles.sectionTitle}>encuéntranos cerca de ti</h3>
          <button style={styles.storeLocatorButton}>UBICADOR DE TIENDAS</button>
          <h3 style={{ ...styles.sectionTitle, marginTop: '30px' }}>el club de correo exclusivo</h3>
          <p style={styles.emailClubText}>Déjanos tus datos y no te arrepentirás.</p>
          <div style={styles.emailInputContainer}>
            <input type="email" placeholder="tu correo electrónico" style={styles.emailInput} />
            <button style={styles.emailSubmitButton}>&rarr;</button>
          </div>
          <div style={styles.socialIcons}>
            {/* Asegúrate de tener Font Awesome o reemplazar estos iconos */}
            <a href="https://facebook.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-facebook-f"></i></a>
            <a href="https://instagram.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-instagram"></i></a>
            <a href="https://tiktok.com" target="_blank" rel="noopener noreferrer" style={styles.socialIcon}><i className="fab fa-tiktok"></i></a>
          </div>
        </div>

        {/* Sección 3: Necesitas ayuda? */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>necesitas ayuda?</h3>
          <ul style={styles.linkListSingle}>
            <li><a href="#" style={styles.link}>Envíos y devoluciones</a></li> {/* "shipping & returns" */}
            <li><Link to="/contacto" style={styles.link}>Contacta con nosotros</Link></li> {/* "contact us" */}
            <li><a href="#" style={styles.link}>Venta al por mayor</a></li> {/* "wholesale" */}
            <li><Link to="/privacidad" style={styles.link}>Política de Privacidad</Link></li> {/* Enlace a "Privacidad" */}
            <li><a href="#" style={styles.link}>Términos del servicio</a></li> {/* "terms of service" */}
            <li><a href="#" style={styles.link}>Preguntas frecuentes</a></li> {/* "frequently asked questions" */}
            <li><a href="#" style={styles.link}>Mapa del sitio</a></li> {/* "sitemap" */}
          </ul>
        </div>
      </div>

      {/* Sección de créditos "Titulizado por Alberto Navarro" */}
      <div style={styles.creditsBar}>
        <p style={styles.creditsText}>Titulizado por Alberto Navarro</p>
      </div>

      {/* Barra inferior "FREE VARIETY PACK" - Descomenta si la necesitas, considera si pertenece aquí */}
      {/* <div style={styles.bottomBar}>
        <span style={styles.bottomBarText}>PAQUETE DE VARIEDADES GRATIS</span>
        <button style={styles.bottomBarClose}>&times;</button>
      </div> */}
    </footer>
  );
};

const styles = {
  footerContainer: {
    // Fondo con la imagen de footer2.png de public/media
    backgroundImage: "url('/media/footer2.png')", // Ruta relativa a la carpeta 'public'
    backgroundSize: 'cover', // Cubrir toda el área
    backgroundPosition: 'center', // Centrar la imagen
    backgroundRepeat: 'no-repeat', // No repetir la imagen
    backgroundColor: '#F8F6F1', // Color de fondo de respaldo
    padding: '60px 20px 20px 20px', // Ajuste el padding inferior para la barra de créditos
    color: '#333',
    fontFamily: "'Poppins', sans-serif",
    borderTop: '1px solid #eee',
    boxShadow: '0 -2px 10px rgba(0,0,0,0.05)',
  },
  footerContent: {
    display: 'flex',
    justifyContent: 'space-around',
    flexWrap: 'wrap',
    maxWidth: '1200px',
    margin: '0 auto',
    gap: '40px',
    marginBottom: '30px', // Espacio entre el contenido principal del footer y la barra de créditos
  },
  section: {
    flex: '1 1 280px',
